function formatDate(str) {
  if (!str) return '—';
  return new Date(str).toLocaleDateString('en-GB', {
    day: '2-digit',
    month: '2-digit',
    year: '2-digit'
  });
}
function destBadge(type) {
  if (!type) return '<span class="badge badge-stock">—</span>';
  if (type === 'scrap_weee') return '<span class="badge badge-scrap-weee">WEEE Scrap</span>';
  if (type.startsWith('scrap')) return '<span class="badge badge-scrap">Scrap</span>';
  if (type === 'stock') return '<span class="badge badge-stock">Stock</span>';
  if (type === 'asset') return '<span class="badge badge-asset">Asset</span>';
  return '<span class="badge badge-stock">' + type + '</span>';
}
function renderStripped(parts) {
  var tbody = document.getElementById('table_body');
  var count = document.getElementById('count');
  if (!tbody) return;
  count.textContent = parts.length + ' part' + (parts.length !== 1 ? 's' : '');
  if (!parts.length) {
    tbody.innerHTML = '<tr><td colspan="9" class="empty">No parts removed yet</td></tr>';
    return;
  }
  tbody.innerHTML = parts.map(function (r) {
    var makeModel = [r.part_make, r.part_model].filter(Boolean).join(' · ') || '—';
    var location = r.installed_in_ref ? 'In: ' + r.installed_in_ref : r.current_location_code ? r.current_location_code + ' — ' + r.current_location_name : '—';
    var overdue = r.is_overdue ? '<span class="badge badge-overdue">Overdue</span>' : r.disposition_due ? formatDate(r.disposition_due) : '—';
    var battery = r.is_battery ? ' 🔋' : '';
    return '<tr>' + '<td><span class="part-ref">' + (r.part_ref || '—') + '</span></td>' + '<td><span class="part-type">' + (r.part_type || '—') + battery + '</span></td>' + '<td>' + makeModel + '</td>' + '<td style="font-family:monospace;font-size:11px">' + (r.serial_number || '—') + '</td>' + '<td><span class="grade">' + (r.condition_grade || '—') + '</span></td>' + '<td>' + destBadge(r.destination_type) + '</td>' + '<td style="font-size:11px;color:#5f5e5a">' + location + '</td>' + '<td style="font-size:11px">' + formatDate(r.removed_date) + '</td>' + '<td style="font-size:11px">' + overdue + '</td>' + '</tr>';
  }).join('');
}
function renderRepairScraps(scraps) {
  var tbody = document.getElementById('scrap_body');
  var count = document.getElementById('scrap_count');
  if (!tbody) return;
  count.textContent = (scraps || []).length + ' part' + ((scraps || []).length !== 1 ? 's' : '');
  if (!scraps || !scraps.length) {
    tbody.innerHTML = '<tr><td colspan="6" class="empty">No repair scraps logged</td></tr>';
    return;
  }
  tbody.innerHTML = scraps.map(function (r) {
    return '<tr>' + '<td><span class="part-ref-scrap">' + (r.part_ref || '—') + '</span></td>' + '<td><span class="part-type">' + (r.part_type || '—') + '</span></td>' + '<td style="font-size:11px;color:#5f5e5a">' + (r.removal_notes || '—') + '</td>' + '<td style="font-size:11px">' + (r.removed_by || '—') + '</td>' + '<td style="font-size:11px">' + formatDate(r.removed_date) + '</td>' + '<td>' + destBadge(r.destination_type) + '</td>' + '</tr>';
  }).join('');
}
function render(model) {
  renderStripped(model.parts || []);
  renderRepairScraps(model.repairScraps || []);
}
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function () {
  render(appsmith.model);
});

